import{_ as a}from"./chunks/微笑狼的公开仓库.gGdYP2E_.js";import{_ as e,o as d,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"自动打标签使用说明","description":"","frontmatter":{},"headers":[],"relativePath":"cn/Other/auto-tagging.md","filePath":"cn/Other/auto-tagging.md","lastUpdated":1781962217000}'),c={name:"cn/Other/auto-tagging.md"};function i(l,t,n,s,p,h){return d(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="自动打标签使用说明" tabindex="-1">自动打标签使用说明 <a class="header-anchor" href="#自动打标签使用说明" aria-label="Permalink to &quot;自动打标签使用说明&quot;">​</a></h1><p>自动打标签在：</p><p>系统配置 -&gt; 其他设置 -&gt; 自动打标签</p><p>这个功能会帮图片自动生成标签，适合后面做搜索、随机图筛选、访客图库筛选、年龄分级访问控制。</p><h2 id="自动打标签能做什么" tabindex="-1">自动打标签能做什么 <a class="header-anchor" href="#自动打标签能做什么" aria-label="Permalink to &quot;自动打标签能做什么&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>说明</th></tr></thead><tbody><tr><td>生成内容标签</td><td>例如人物、场景、物体、画风等标签。</td></tr><tr><td>生成角色标签</td><td>对动漫图、插画图里的角色更有用。</td></tr><tr><td>补方向标签</td><td>自动补 <code>landscape</code>（横图）、<code>portrait</code>（竖图）、<code>square</code>（方图）。</td></tr><tr><td>补图片分级</td><td>自动保存 <code>G/S/Q/E</code>（全年龄/敏感/可疑/露骨）分级结果。</td></tr><tr><td>上传时自动打标</td><td>开启后，新上传的图片会自动进入打标签流程。</td></tr><tr><td>批量打标签</td><td>可以给全部文件夹或指定文件夹里的旧图片批量补标签。</td></tr></tbody></table><h2 id="需要先准备什么" tabindex="-1">需要先准备什么 <a class="header-anchor" href="#需要先准备什么" aria-label="Permalink to &quot;需要先准备什么&quot;">​</a></h2><p>你需要准备至少一个可以访问的 <code>Hugging Face Space</code>（Hugging Face 空间）地址。</p><p>推荐从微笑狼的 <code>wd-tagger</code>（图片标签识别空间）复制一个到自己的账号下使用：</p><p><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>（微笑狼原始空间地址）</p><p>也可以先临时使用公开空间，但公开空间很多人一起用，容易排队、变慢或临时不可用。自己的空间更稳定，也更适合长期自动打标签。</p><h2 id="复制微笑狼的空间" tabindex="-1">复制微笑狼的空间 <a class="header-anchor" href="#复制微笑狼的空间" aria-label="Permalink to &quot;复制微笑狼的空间&quot;">​</a></h2><p>操作顺序如下：</p><ol><li>登录 <code>Hugging Face</code>（Hugging Face）。</li><li>打开 <code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>（微笑狼原始空间地址）。</li></ol><p><img src="'+a+`" alt="微笑狼的公开仓库" loading="lazy"></p><ol start="3"><li>点击页面右上角的三个点。</li><li>选择 <code>Duplicate this Space</code>（复制这个空间）。</li><li>空间名称可以保持默认，也可以改成你喜欢的名字，例如 <code>wd-tagger</code>（标签识别空间）。</li><li>可见性建议选 <code>Public</code>（公开）。公开空间更方便图床调用。</li><li>硬件先用默认免费配置即可。后面如果排队明显，再考虑升级。</li><li>点击创建，等待空间构建完成。</li></ol><p>构建完成后，进入你自己的空间页面。地址一般长这样：</p><p><code>https://huggingface.co/spaces/你的用户名/wd-tagger</code>（你复制后的空间页面地址）</p><p>直接复制浏览器地址栏里的链接，粘贴到图床的 <code>Space URLs</code>（空间地址）里就可以。</p><h2 id="多个-space-urls-怎么填" tabindex="-1">多个 Space URLs 怎么填 <a class="header-anchor" href="#多个-space-urls-怎么填" aria-label="Permalink to &quot;多个 Space URLs 怎么填&quot;">​</a></h2><p><code>Space URLs</code>（空间地址）一行填一个。</p><p>例如：</p><table tabindex="0"><thead><tr><th>填写内容</th><th>说明</th></tr></thead><tbody><tr><td><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code></td><td>微笑狼公开空间，适合临时测试。</td></tr><tr><td><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code></td><td>直接复制空间页面链接。</td></tr><tr><td><code>https://huggingface.co/spaces/你的用户名/wd-tagger</code></td><td>你自己复制后的空间页面链接。</td></tr></tbody></table><p>可以填多个地址。系统会同时使用多个空间处理图片，速度会更快。<br> 如果其中一个空间暂时不可用，其他空间还能继续处理。</p><h2 id="页面选项怎么填" tabindex="-1">页面选项怎么填 <a class="header-anchor" href="#页面选项怎么填" aria-label="Permalink to &quot;页面选项怎么填&quot;">​</a></h2><table tabindex="0"><thead><tr><th>选项</th><th>建议</th></tr></thead><tbody><tr><td><code>Space URLs</code>（空间地址）</td><td>填你复制好的空间地址。建议至少填 1 个。</td></tr><tr><td>目标文件夹</td><td>不选就是全部文件夹；只想处理某个目录时再选择目录。</td></tr><tr><td>识别模型</td><td>默认选 <code>wd-swinv2-tagger-v3</code>（推荐模型）即可。</td></tr><tr><td>通用标签阈值</td><td>默认值适合大多数图片。值越低，标签越多；值越高，标签越少。</td></tr><tr><td>角色标签阈值</td><td>默认值偏稳，适合避免乱识别角色。</td></tr><tr><td>使用 <code>MCut</code>（自动阈值）</td><td>不确定时可以先不开。想让模型自己判断标签数量时再打开。</td></tr><tr><td>上传时自动打标</td><td>想让新上传图片自动有标签，就打开。</td></tr><tr><td>开始打标签</td><td>手动给旧图片批量补标签。</td></tr></tbody></table><h2 id="推荐配置" tabindex="-1">推荐配置 <a class="header-anchor" href="#推荐配置" aria-label="Permalink to &quot;推荐配置&quot;">​</a></h2><p>刚开始可以这样填：</p><table tabindex="0"><thead><tr><th>选项</th><th>推荐值</th></tr></thead><tbody><tr><td>识别模型</td><td><code>wd-swinv2-tagger-v3</code>（推荐模型）</td></tr><tr><td>通用标签阈值</td><td><code>0.35</code>（默认值）</td></tr><tr><td>角色标签阈值</td><td><code>0.85</code>（默认值）</td></tr><tr><td>使用 <code>MCut</code>（自动阈值）</td><td>先关闭</td></tr><tr><td>上传时自动打标</td><td>看需求开启</td></tr></tbody></table><p>如果你发现标签太多，可以把通用标签阈值调高一点。<br> 如果你发现标签太少，可以把通用标签阈值调低一点。</p><h2 id="批量打标签怎么用" tabindex="-1">批量打标签怎么用 <a class="header-anchor" href="#批量打标签怎么用" aria-label="Permalink to &quot;批量打标签怎么用&quot;">​</a></h2><ol><li>先填好 <code>Space URLs</code>（空间地址）。</li><li>选择目标文件夹。</li><li>点击开始打标签。</li><li>等待进度跑完。</li></ol><p>目标文件夹留空时，会处理全部文件夹。</p><p>批量打标签适合处理旧图片。新图片建议打开上传时自动打标，后面就不用每次手动跑。</p><h2 id="上传时自动打标" tabindex="-1">上传时自动打标 <a class="header-anchor" href="#上传时自动打标" aria-label="Permalink to &quot;上传时自动打标&quot;">​</a></h2><p>打开上传时自动打标后，新上传的图片会自动调用你填写的 <code>Space URLs</code>（空间地址）。</p><p>这个开关适合长期使用。<br> 如果你的空间正在排队，上传本身会先完成，打标签会在后面继续处理。</p><h2 id="哪些图片会被处理" tabindex="-1">哪些图片会被处理 <a class="header-anchor" href="#哪些图片会被处理" aria-label="Permalink to &quot;哪些图片会被处理&quot;">​</a></h2><p>自动打标签主要处理图片文件。</p><p>已经有完整标签、方向、分级、宽高信息的图片会跳过，不会重复浪费空间调用次数。<br> 缺什么就补什么，比如只缺方向标签时，系统会尽量只补方向；缺内容标签时，才会调用空间生成内容标签。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="为什么建议复制自己的空间" tabindex="-1">为什么建议复制自己的空间 <a class="header-anchor" href="#为什么建议复制自己的空间" aria-label="Permalink to &quot;为什么建议复制自己的空间&quot;">​</a></h3><p>公开空间是大家一起用的，别人也在排队。<br> 复制到自己的账号后，空间主要给你的图床使用，速度和稳定性都会更好。</p><h3 id="空间一直在启动怎么办" tabindex="-1">空间一直在启动怎么办 <a class="header-anchor" href="#空间一直在启动怎么办" aria-label="Permalink to &quot;空间一直在启动怎么办&quot;">​</a></h3><p>第一次打开或长时间没人用时，空间可能需要启动一会儿。<br> 可以先打开你的空间页面，等页面能正常识别图片后，再回图床里开始打标签。</p><h3 id="space-地址要怎么复制" tabindex="-1">Space 地址要怎么复制 <a class="header-anchor" href="#space-地址要怎么复制" aria-label="Permalink to &quot;Space 地址要怎么复制&quot;">​</a></h3><p>打开你的 <code>Hugging Face Space</code>（Hugging Face 空间）页面，直接复制浏览器地址栏里的链接就行。</p><p>例如：</p><p><code>https://huggingface.co/spaces/lintonxue00/wd-tagger</code>（空间页面链接）</p><p><code>https://huggingface.co/spaces/SmilingWolf/wd-tagger</code>（微笑狼公开空间链接）</p><h3 id="可以填多个空间吗" tabindex="-1">可以填多个空间吗 <a class="header-anchor" href="#可以填多个空间吗" aria-label="Permalink to &quot;可以填多个空间吗&quot;">​</a></h3><p>可以。每行一个空间地址。<br> 多个空间会一起处理，适合图片比较多的时候。</p><h3 id="标签语言为什么是英文" tabindex="-1">标签语言为什么是英文 <a class="header-anchor" href="#标签语言为什么是英文" aria-label="Permalink to &quot;标签语言为什么是英文&quot;">​</a></h3><p>微笑狼的模型输出的是英文标签，这是正常的。<br> 这些标签主要用于搜索、筛选、随机图接口和公开图库筛选。</p><h3 id="分级标签有什么用" tabindex="-1">分级标签有什么用 <a class="header-anchor" href="#分级标签有什么用" aria-label="Permalink to &quot;分级标签有什么用&quot;">​</a></h3><p>分级结果会配合安全设置里的访问模式使用。<br> 例如访客模式限制了年龄分级后，公开浏览、随机图像等功能会按规则过滤图片。</p><h2 id="简单流程" tabindex="-1">简单流程 <a class="header-anchor" href="#简单流程" aria-label="Permalink to &quot;简单流程&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>登录 Hugging Face</span></span>
<span class="line"><span>-&gt; 打开 SmilingWolf/wd-tagger</span></span>
<span class="line"><span>-&gt; Duplicate this Space</span></span>
<span class="line"><span>-&gt; 等空间构建完成</span></span>
<span class="line"><span>-&gt; 复制自己的 Space 地址</span></span>
<span class="line"><span>-&gt; 回图床填写 Space URLs</span></span>
<span class="line"><span>-&gt; 选择模型和阈值</span></span>
<span class="line"><span>-&gt; 开始打标签或开启上传时自动打标</span></span></code></pre></div>`,58)])])}const f=e(c,[["render",i]]);export{b as __pageData,f as default};
